const SESSION_ID = 'YOUR_SESSION_ID';

const order = $input.first().json.body || $input.first().json;

const customerName = order.customer
  ? (order.customer.first_name + ' ' + (order.customer.last_name || '')).trim()
  : 'Customer';

const phone = order.customer && order.customer.phone
  ? order.customer.phone.replace(/[^0-9]/g, '')
  : (order.billing_address && order.billing_address.phone
    ? order.billing_address.phone.replace(/[^0-9]/g, '')
    : '');

if (!phone) {
  return [{ json: { error: 'No phone number found', order_id: order.id || order.order_number } }];
}

const orderNumber = order.order_number || order.name || order.id;
const total = order.total_price || '0.00';
const currency = order.currency || 'USD';

const items = (order.line_items || []).map(item =>
  item.title + ' x' + item.quantity
).join(', ');

const message = `Hi ${customerName}! Your order #${orderNumber} has been confirmed.\n\nItems: ${items}\nTotal: ${currency} ${total}\n\nWe'll send you tracking details once your order ships. Thank you for your purchase!`;

return [{
  json: {
    session_id: SESSION_ID,
    chat_id: phone + '@c.us',
    message: message,
    customer_name: customerName,
    order_number: orderNumber,
    phone: phone
  }
}];

const input = $input.first().json;
return [{ json: {
  status: 'sent',
  customer: input.customer_name || $('Format Order Message').first().json.customer_name,
  order: $('Format Order Message').first().json.order_number,
  message_id: input.id || 'N/A'
} }];

return [{ json: {
  status: 'skipped',
  reason: 'No phone number on order',
  order: $('Format Order Message').first().json.order_number
} }];
